          <div class="flex flex-col gap-3">
            <a href="https://conduitimpactcapital.com" target="_blank" rel="noopener" class="text-sm text-white/60 hover:text-white no-underline transition-colors">Conduit Impact Capital &#x2197;</a>
            <button onclick="openIR();trackAction('PAGE.FORINVESTORS')" class="text-sm text-white/60 hover:text-white bg-transparent border-none cursor-pointer text-left p-0 font-sans transition-colors">Investor Relations</button>
          </div>
        </div>
        <div>
          <h4 class="font-mono text-xs tracking-widest uppercase text-white/30 mb-4">Connect</h4>
          <div class="flex flex-col gap-3">
            <a href="https://www.linkedin.com/company/pooledimpact" target="_blank" rel="noopener" class="text-sm text-white/60 hover:text-white no-underline transition-colors">LinkedIn &#x2197;</a>
            <button onclick="openIR();trackAction('PAGE.GETTOUCH')" class="text-sm text-white/60 hover:text-white bg-transparent border-none cursor-pointer text-left p-0 font-sans transition-colors">Contact Us</button>
          </div>
        </div>
      </div>
    </div>
    <div class="border-t border-white/10 pt-6 flex flex-col lg:flex-row justify-between gap-4">
      <p class="font-mono text-xs text-white/50">&copy; 2026 Pooled Impact Corporation. All rights reserved.</p>
      <p class="font-mono text-xs text-white/45 max-w-md lg:text-right leading-loose">This website is for informational purposes only and does not constitute an offer to sell or solicitation to buy any securities. Conduit Impact Capital is a separate investment vehicle.</p>
    </div>
  </div>
</footer>

<script>
// ── IndexedDB ─────────────────────────────────────────────────────────────
const PI_DB = 'PooledImpact_v1';
let piDB = null;
function genHash(n=20){const c='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';return Array.from(crypto.getRandomValues(new Uint8Array(n))).map(b=>c[b%c.length]).join('');}
function initDB(){return new Promise(res=>{const r=indexedDB.open(PI_DB,1);r.onupgradeneeded=e=>{const db=e.target.result;['Visitor','BrowserInfo','FormSchema'].forEach(s=>{if(!db.objectStoreNames.contains(s))db.createObjectStore(s,{keyPath:'hash'});});if(!db.objectStoreNames.contains('Actions')){const a=db.createObjectStore('Actions',{keyPath:'id',autoIncrement:true});a.createIndex('visitorHash','visitorHash',{unique:false});}if(!db.objectStoreNames.contains('Forms')){const f=db.createObjectStore('Forms',{keyPath:'id',autoIncrement:true});f.createIndex('visitorHash','visitorHash',{unique:false});}if(!db.objectStoreNames.contains('GitSync')){const g=db.createObjectStore('GitSync',{keyPath:'id',autoIncrement:true});g.createIndex('synced','synced',{unique:false});}};r.onsuccess=e=>{piDB=e.target.result;res(piDB);};r.onerror=()=>res(null);});}
const dbPut=(s,o)=>{if(!piDB)return;piDB.transaction(s,'readwrite').objectStore(s).put(o);};
const dbAdd=(s,o)=>{if(!piDB)return;piDB.transaction(s,'readwrite').objectStore(s).add(o);};
const dbGet=(s,k)=>new Promise(res=>{if(!piDB){res(null);return;}const r=piDB.transaction(s,'readonly').objectStore(s).get(k);r.onsuccess=()=>res(r.result||null);r.onerror=()=>res(null);});

// ── Visitor ────────────────────────────────────────────────────────────────
let VISITOR_HASH=null,SITE_CONFIG=null;
async function initVisitor(){let h=localStorage.getItem('pi_vh');if(!h){h=genHash(20);localStorage.setItem('pi_vh',h);}VISITOR_HASH=h;const existing=await dbGet('Visitor',h);const now=new Date().toISOString();if(!existing){dbPut('Visitor',{hash:h,firstSeen:now,lastSeen:now,visits:1});dbPut('BrowserInfo',{hash:h,userAgent:navigator.userAgent,language:navigator.language,timezone:Intl.DateTimeFormat().resolvedOptions().timeZone,viewport:window.innerWidth+'x'+window.innerHeight,referrer:document.referrer||'direct',hostname:window.location.hostname,url:window.location.href,recordedAt:now});queueSync('NEW_VISITOR',{hash:h,firstSeen:now});}else{dbPut('Visitor',{...existing,lastSeen:now,visits:(existing.visits||1)+1});}await loadSiteConfig();startTimeTracking();}
async function loadSiteConfig(){const host=window.location.hostname;const url=host.includes('pooledimpact.com')?'https://raw.githubusercontent.com/Sudo-Conduit/Sentinel/main/pooledimpact/website/config/pooledimpact.json':null;if(!url){SITE_CONFIG={url:host,saveType:'0',save:{github:'Sudo-Conduit/Sentinel'}};return;}try{const r=await fetch(url);SITE_CONFIG=r.ok?await r.json():{url:host,saveType:'0',save:{github:'Sudo-Conduit/Sentinel'}};}catch{SITE_CONFIG={url:host,saveType:'0',save:{github:'Sudo-Conduit/Sentinel'}};}}
function trackAction(type,meta={}){if(!VISITOR_HASH)return;const a={visitorHash:VISITOR_HASH,type,meta:JSON.stringify(meta),ts:new Date().toISOString()};dbAdd('Actions',a);queueSync('ACTION',a);}
function startTimeTracking(){[[5,'TIME.SECS.05'],[60,'TIME.MINUTE.01'],[180,'TIME.MINUTE.03'],[300,'TIME.MINUTE.05'],[600,'TIME.MINUTE.10']].forEach(([s,l])=>setTimeout(()=>trackAction(l),s*1000));}
function queueSync(type,payload){dbAdd('GitSync',{type,payload:JSON.stringify(payload),ts:new Date().toISOString(),synced:0});}
setInterval(()=>{if(!piDB||!SITE_CONFIG)return;const tx=piDB.transaction('GitSync','readwrite');const req=tx.objectStore('GitSync').index('synced').getAll(0);req.onsuccess=()=>{(req.result||[]).forEach(r=>{piDB.transaction('GitSync','readwrite').objectStore('GitSync').put({...r,synced:1,syncedAt:new Date().toISOString()});});};},30000);
function seedFormSchemas(){dbPut('FormSchema',{hash:'SCHEDULECONVO',fields:['name','email','phone','company','source']});dbPut('FormSchema',{hash:'STARTCONVERSATION',fields:['name','email','phone','company','message']});}

// ── Panel ──────────────────────────────────────────────────────────────────
function openPanel(){document.getElementById('slide-panel').classList.remove('translate-x-full');document.getElementById('slide-backdrop').classList.remove('opacity-0','pointer-events-none');document.body.style.overflow='hidden';}
function closePanel(){document.getElementById('slide-panel').classList.add('translate-x-full');document.getElementById('slide-backdrop').classList.add('opacity-0','pointer-events-none');document.body.style.overflow='';}
function submitPanel(){const name=document.getElementById('pf-name').value.trim();const email=document.getElementById('pf-email').value.trim();const org=document.getElementById('pf-org').value.trim();const phone=document.getElementById('pf-phone').value.trim();const err=document.getElementById('panel-error');if(!name){err.classList.remove('hidden');err.textContent='Please enter your name.';return;}if(!email||!/^[^@]+@[^@]+\.[a-zA-Z]{2,8}$/.test(email)){err.classList.remove('hidden');err.textContent='Please enter a valid email.';return;}if(!org){err.classList.remove('hidden');err.textContent='Please enter your organization.';return;}err.classList.add('hidden');dbAdd('Forms',{visitorHash:VISITOR_HASH,formName:'SCHEDULECONVO',data:JSON.stringify({name,email,phone,org,source:document.getElementById('pf-source').value}),ts:new Date().toISOString()});trackAction('FORM.SCHEDULECONVO',{name,org});const sub=encodeURIComponent('Investor Introduction Request — Pooled Impact');const body=encodeURIComponent('Name: '+name+'\nOrg: '+org+'\nPhone: '+(phone||'N/A')+'\nSource: '+(document.getElementById('pf-source').value||'N/A'));window.open('mailto:will.fobbs@pooledimpact.com?subject='+sub+'&body='+body);document.getElementById('panel-form').classList.add('hidden');document.getElementById('panel-thanks').classList.remove('hidden');}

// ── IR Page ────────────────────────────────────────────────────────────────
function openIR(){document.getElementById('ir-page').classList.remove('opacity-0','pointer-events-none');document.body.style.overflow='hidden';}
function closeIR(){document.getElementById('ir-page').classList.add('opacity-0','pointer-events-none');document.body.style.overflow='';}
function submitIR(){const name=document.getElementById('ir-name').value.trim();const email=document.getElementById('ir-email').value.trim();const phone=document.getElementById('ir-phone').value.trim();const err=document.getElementById('ir-error');if(!name){err.classList.remove('hidden');err.textContent='Please enter your name.';return;}if(!email||!/^[^@]+@[^@]+\.[a-zA-Z]{2,8}$/.test(email)){err.classList.remove('hidden');err.textContent='Please enter a valid email.';return;}err.classList.add('hidden');dbAdd('Forms',{visitorHash:VISITOR_HASH,formName:'STARTCONVERSATION',data:JSON.stringify({name,email,phone,org:document.getElementById('ir-org').value,message:document.getElementById('ir-msg').value}),ts:new Date().toISOString()});trackAction('FORM.STARTCONVERSATION',{name});const sub=encodeURIComponent('Investor Relations Inquiry — Pooled Impact');const body=encodeURIComponent('Name: '+name+'\nPhone: '+(phone||'N/A')+'\nOrg: '+(document.getElementById('ir-org').value||'N/A')+'\nMessage: '+(document.getElementById('ir-msg').value||'None'));window.open('mailto:will.fobbs@pooledimpact.com?subject='+sub+'&body='+body);document.getElementById('ir-form').classList.add('hidden');document.getElementById('ir-thanks').classList.remove('hidden');}

// ── Helpers ────────────────────────────────────────────────────────────────
function gotoSection(id){const el=document.getElementById(id);if(el)el.scrollIntoView({behavior:'smooth'});}

// ── Alpine ─────────────────────────────────────────────────────────────────
document.addEventListener('alpine:init', () => {
  Alpine.data('pi', () => ({
    mobileOpen: false,
    init() { initDB().then(() => { initVisitor(); seedFormSchemas(); }); },
    trackAction(type, meta={}) { trackAction(type, meta); }
  }));
});
</script>
</body>
</html>